import AsyncStorage from '@react-native-async-storage/async-storage';

const DATA_KEY = 'user_data';

// Save user preferences
const saveUserData = async (userData) => {
  try {
    await AsyncStorage.setItem(DATA_KEY, JSON.stringify(userData));
  } catch (error) {
    console.error('Error saving user data:', error);
  }
};

// Retrieve user preferences
const getUserData = async () => {
  try {
    const userData = await AsyncStorage.getItem(DATA_KEY);
    return userData ? JSON.parse(userData) : null;
  } catch (error) {
    console.error('Error retrieving user data:', error);
    return null;
  }
};

// Update specific fields in user preferences
const updateUserField = async (fieldName, fieldValue) => {
  try {
    const userData = await getUserData();
    if (userData) {
      userData[fieldName] = fieldValue;
      await saveUserData(userData);
    } else {
      console.warn('No user data found');
    }
  } catch (error) {
    console.error('Error updating user field:', error);
  }
};

// Remove user preferences
const removeUserData = async () => {
  try {
    await AsyncStorage.removeItem(DATA_KEY);
  } catch (error) {
    console.error('Error removing user data:', error);
  }
};

export { saveUserData, getUserData, updateUserField, removeUserData };